#include<bits/stdc++.h>
using namespace std;
const int N=805,mod=1000000007;
int n,m,k,a[N][N],dp[N][N][20][2],ans;
int main()
{
    cin>>n>>m>>k;
    k++;
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            cin>>a[i][j];
            a[i][j]%=k;
            dp[i][j][a[i][j]][0]=1;
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            for(int k2=0;k2<=k;k2++)
            {
                dp[i][j][k2][0]=(dp[i][j][k2][0]+dp[i-1][j][(k2-a[i][j]+k)%k][1]+dp[i][j-1][(k2-a[i][j]+k)%k][1])%mod;
                dp[i][j][k2][1]=(dp[i-1][j][(k2+a[i][j])%k][0]+dp[i][j-1][(k2+a[i][j])%k][0])%mod;
            }
            ans+=dp[i][j][0][1];
            ans%=mod;
        }
    }
    cout<<ans;
}
